@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:SoftwareApplication ;
                    schema1:name "SeisUnix" ;
                    schema1:url "https://wiki.seismic-unix.org/" ;
                    schema1:version "44R27" ] ;
            sh:resultMessage "An instrument should have a category classification from a controlled vocabulary (schema:category)." ;
            sh:resultPath schema1:category ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "An instrument should have a category classification from a controlled vocabulary (schema:category)." ;
                    sh:minCount 1 ;
                    sh:path schema1:category ;
                    sh:severity sh:Warning ] ] .

